+    fn edge(from: &str, to: &str, dependency_name: &str) -> CargoPathDependencyEdge {
+        CargoPathDependencyEdge {
+            from: PathBuf::from(from),
+            to: PathBuf::from(to),
+            dependency_name: dependency_name.to_string(),
+        }
